"problem_statement": "Reconstruct a valid sequence of sibling-merge operations to transform an initial rooted tree T_initial with N nodes into a final rooted tree T_final with M nodes.",
"analysis": {
"operation_definition": "A sibling-merge operation merges two adjacent siblings into a single node, preserving parent-child relationships while reducing child count.",
"key_constraints": [
"Root mapping must be preserved",
"Children of a node in T_final must correspond to contiguous blocks of children/descendants in T_initial",
"Relative order of children must be maintained"
]
},
"algorithm": {
"approach": "Recursive partitioning of children",
"logic": "For a node U in T_final, partition the children of its corresponding node u in T_initial into m contiguous non-empty segments S_1 to S_m, where each segment S_i merges into child C_i of U.",
"reconstruction_method": "Identify adjacent sibling pairs (c_i, c_{i+1}) that belong to the same partition segment S_j. Perform merges via tree traversal (DFS) to ensure structural integrity."
}
},
"metadata": {
"schema_version": "v1",
"complexity": "tree-transformation-logic"
}
}

